import{_ as o,C as r,o as a,c as s,a4 as i,E as n}from"./chunks/framework.BY9PERBP.js";const m=JSON.parse('{"title":"Editor & clipboard","description":"A pared-back text editor beside the shared clipboard, shown live — a runnable JSVision example in the browser.","frontmatter":{"title":"Editor & clipboard","description":"A pared-back text editor beside the shared clipboard, shown live — a runnable JSVision example in the browser."},"headers":[],"relativePath":"apps/editor.md","filePath":"apps/editor.md"}'),d={name:"apps/editor.md"};function l(p,e,c,h,b,g){const t=r("PlayExample");return a(),s("div",null,[e[0]||(e[0]=i('<h1 id="editor-clipboard" tabindex="-1">Editor &amp; clipboard <a class="header-anchor" href="#editor-clipboard" aria-label="Permalink to &quot;Editor &amp; clipboard&quot;">​</a></h1><p>A text editor with the clipboard made visible: type and select in the top window, and whatever you cut or copy appears in the <strong>Clipboard</strong> window below. That second window is not a preview — it hosts the clipboard, which in JSVision is itself an editor, so you can select inside it and paste exactly what you selected.</p><p>Pared back to the clipboard story on purpose: there is no file handling and no find/replace, so nothing here needs a file system.</p><p>Try <strong>Shift</strong>+arrows or a mouse drag to select, then <strong>Ctrl+C</strong> / <strong>Ctrl+X</strong> / <strong>Ctrl+V</strong> — or the classic <strong>Ctrl+Ins</strong> / <strong>Shift+Ins</strong> / <strong>Shift+Del</strong>. <strong>Ctrl+Z</strong> undoes, <strong>Ctrl+Y</strong> redoes.</p>',4)),n(t,{id:"apps/editor",title:"Editor & clipboard",blurb:"A cut-down text editor beside the shared clipboard, shown live as you cut, copy, and paste."})])}const u=o(d,[["render",l]]);export{m as __pageData,u as default};
